import azure.functions as func
import logging
import json
import base64
import hashlib
import hmac
from typing import Any

app = func.FunctionApp()

# Configuration for message validation
SHARED_SECRET = "your-shared-secret-key"  # Should be stored in Azure Key Vault
ALLOWED_MESSAGE_TYPES = ["JobRequest", "DataProcessing", "AnalyticsTask"]

def verify_message_signature(message_data: bytes, signature: str) -> bool:
    """Verify HMAC signature of the message"""
    expected_signature = hmac.new(
        SHARED_SECRET.encode(),
        message_data,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def deserialize_message(message_body: str) -> dict:
    """Safely deserialize JSON message instead of pickle"""
    try:
        return json.loads(message_body)
    except json.JSONDecodeError as e:
        logging.error(f"Failed to deserialize message: {e}")
        raise ValueError("Invalid message format")

def validate_message_structure(data: dict) -> bool:
    """Validate message has required fields and correct types"""
    required_fields = ["message_type", "payload", "timestamp", "signature"]
    
    if not all(field in data for field in required_fields):
        return False
    
    if data["message_type"] not in ALLOWED_MESSAGE_TYPES:
        return False
    
    if not isinstance(data["payload"], dict):
        return False
    
    return True

def process_job_request(payload: dict) -> dict:
    """Process job request payload"""
    job_id = payload.get("job_id")
    job_type = payload.get("job_type")
    parameters = payload.get("parameters", {})
    
    logging.info(f"Processing job request: {job_id}, type: {job_type}")
    
    # Process the job based on type
    result = {
        "job_id": job_id,
        "status": "completed",
        "result": f"Processed {job_type} with parameters {parameters}"
    }
    
    return result

def process_data_processing(payload: dict) -> dict:
    """Process data processing payload"""
    data_id = payload.get("data_id")
    operation = payload.get("operation")
    
    logging.info(f"Processing data: {data_id}, operation: {operation}")
    
    result = {
        "data_id": data_id,
        "status": "completed",
        "operation": operation
    }
    
    return result

def process_analytics_task(payload: dict) -> dict:
    """Process analytics task payload"""
    task_id = payload.get("task_id")
    metrics = payload.get("metrics", [])
    
    logging.info(f"Processing analytics task: {task_id}")
    
    result = {
        "task_id": task_id,
        "status": "completed",
        "metrics_processed": len(metrics)
    }
    
    return result

@app.service_bus_queue_trigger(
    arg_name="msg",
    queue_name="job-queue",
    connection="ServiceBusConnection"
)
def process_queue_message(msg: func.ServiceBusMessage) -> None:
    """
    Azure Function to process Service Bus queue messages
    Uses JSON deserialization instead of pickle for security
    """
    try:
        message_body = msg.get_body().decode('utf-8')
        logging.info(f"Received message from queue")
        
        # Deserialize message using JSON (secure alternative to pickle)
        message_data = deserialize_message(message_body)
        
        # Validate message structure
        if not validate_message_structure(message_data):
            logging.error("Invalid message structure")
            raise ValueError("Message validation failed")
        
        # Verify message signature to ensure authenticity
        message_without_sig = {k: v for k, v in message_data.items() if k != "signature"}
        message_bytes = json.dumps(message_without_sig, sort_keys=True).encode()
        
        if not verify_message_signature(message_bytes, message_data["signature"]):
            logging.error("Message signature verification failed")
            raise ValueError("Invalid message signature")
        
        # Route to appropriate processor based on message type
        message_type = message_data["message_type"]
        payload = message_data["payload"]
        
        if message_type == "JobRequest":
            result = process_job_request(payload)
        elif message_type == "DataProcessing":
            result = process_data_processing(payload)
        elif message_type == "AnalyticsTask":
            result = process_analytics_task(payload)
        else:
            raise ValueError(f"Unknown message type: {message_type}")
        
        logging.info(f"Successfully processed message: {result}")
        
    except ValueError as e:
        logging.error(f"Validation error: {e}")
        # Message will be moved to dead-letter queue after max delivery attempts
        raise
    except Exception as e:
        logging.error(f"Error processing message: {e}")
        raise


